mapper.select:
SELECT /*+ USE_INDEX(t_erp_qc_inspection idx_factory_id, idx_batch_no) */
       id, batch_no, style_code, order_no, result, pass_rate, sample_qty, defect_qty,
       inspector_id, inspector_name, factory_id, status, reject_reason,
       qc_type, size_measure, needle_detect, recheck_count, defect_segment,
       remark, create_by, create_time, update_by, update_time
FROM t_erp_qc_inspection

    AND batch_no LIKE CONCAT('%',#{batchNo},'%')
    AND style_code = #{styleCode}
    AND result = #{result}
    AND status = #{status}
    AND factory_id = #{factoryId}

${params.factoryDataScope}
ORDER BY create_time DESC

mapper.update:
UPDATE t_erp_qc_inspection
result = #{result}, pass_rate = #{passRate}, defect_qty = #{defectQty}, status = #{status}, reject_reason = #{rejectReason}, qc_type = #{qcType}, size_measure = #{sizeMeasure}, needle_detect = #{needleDetect}, recheck_count = #{recheckCount}, defect_segment = #{defectSegment}, update_by = #{updateBy}, update_time = NOW(),
WHERE id = #{id}
